import math
import numpy as np
from collections import defaultdict, Counter

# Preprocessing functions
def preprocess(text):
    # Tokenization
    tokens = text.lower().split()
    # Remove stop words (simplified list)
    stop_words = {'the', 'and', 'of', 'to', 'a', 'in', 'is', 'it', 'that', 'this', 'for', 'on', 'with', 'as'}
    tokens = [word for word in tokens if word not in stop_words]
    # Stemming (basic)
    stems = [word for word in tokens]
    return stems

def train_naive_bayes(corpus, labels):
    # Preprocess all texts
    processed_texts = [preprocess(text) for text, label in zip(corpus, labels)]

    # Count word frequencies per class
    class_counts = defaultdict(int)
    class_word_counts = defaultdict(lambda: defaultdict(int))

    for text, label in zip(processed_texts, labels):
        class_counts[label] += 1
        for word in text:
            class_word_counts[label][word] += 1

    # Total number of words in each class
    class_total_words = {cls: sum(counts.values()) for cls, counts in class_word_counts.items()}

    # Vocabulary
    vocabulary = set()
    for text in processed_texts:
        vocabulary.update(text)

    # Smoothing (Laplace smoothing)
    vocab_size = len(vocabulary)
    class_probabilities = {cls: math.log(class_counts[cls] / len(labels)) for cls in class_counts}
    class_word_probabilities = defaultdict(lambda: defaultdict(float))

    for cls in class_counts:
        for word in vocabulary:
            count = class_word_counts[cls].get(word, 0)
            class_word_probabilities[cls][word] = math.log((count + 1) / (class_total_words[cls] + vocab_size))

    return class_probabilities, class_word_probabilities, vocabulary

def predict_naive_bayes(text, class_probabilities, class_word_probabilities, vocabulary):
    processed_text = preprocess(text)
    log_probabilities = {}

    for cls in class_probabilities:
        log_prob = class_probabilities[cls]
        for word in processed_text:
            log_prob += class_word_probabilities[cls].get(word, math.log(1 / (len(vocabulary) + 1)))
